import json, random, chess

pairs = json.load(open('/app/re.json'))
keys = set()
for pattern, _ in pairs:
    if pattern.startswith('^') and pattern.endswith(r' \d+ \d+$'):
        middle = pattern[1:-len(r' \d+ \d+$')]
